using Microsoft.EntityFrameworkCore;
using Microsoft.Azure.Cosmos;

// Demonstrates two EF Core 9 Cosmos DB breaking changes and their fixes.
class CosmosDbContext : DbContext
{
    public DbSet<Product> Products => Set<Product>();

    protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
    {
        optionsBuilder.UseCosmos(
            "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
            "CatalogDb",
            cosmosOptions =>
            {
                // Breaking change #1 – Synchronous Cosmos I/O now throws.
                // EF Core 9 removed sync-over-async support in the Cosmos provider.
                // Fix: Allow sync if you cannot convert callers to async yet.
                cosmosOptions.HttpClientFactory(() => new HttpClient());
                cosmosOptions.AllowSynchronousQueryExecution(true);
            });
    }

    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        // Breaking change #2 – Default discriminator property changed
        // from "Discriminator" to "$type" in EF Core 9.
        // Existing documents already store "Discriminator", so we must
        // explicitly keep the old name to avoid data mismatch.
        modelBuilder.Entity<Product>()
            .HasDiscriminator<string>("Discriminator");
    }
}

class Product
{
    public string Id { get; set; } = null!;
    public string Name { get; set; } = null!;
}

// Preferred long-term fix: convert sync callers to async.
class ProductService
{
    private readonly CosmosDbContext _db;
    public ProductService(CosmosDbContext db) => _db = db;

    // ✗  Before (EF8): sync was silently allowed
    //     var products = _db.Products.ToList();
    //
    // ✓  After (EF9): use async to avoid the breaking change entirely
    public async Task<List<Product>> GetAllAsync()
        => await _db.Products.ToListAsync();
}

