4. // Demonstrates two EF Core 9 Cosmos DB breaking changes and their fixes.
5. class CosmosDbContext : DbContext
6. {
7.     public DbSet<Product> Products => Set<Product>();
8. 
9.     protected override void OnConfiguring(DbContextOptionsBuilder optionsBuilder)
10.     {
11.         optionsBuilder.UseCosmos(
12.             "AccountEndpoint=https://localhost:8081/;AccountKey=placeholder",
13.             "CatalogDb",
14.             cosmosOptions =>
15.             {
16.                 // Breaking change #1 – Synchronous Cosmos I/O now throws.
17.                 // EF Core 9 removed sync-over-async support in the Cosmos provider.
18.                 // Fix: Allow sync if you cannot convert callers to async yet.
19.                 cosmosOptions.HttpClientFactory(() => new HttpClient());
20.                 cosmosOptions.AllowSynchronousQueryExecution(true);
21.             });
22.     }
23. 
24.     protected override void OnModelCreating(ModelBuilder modelBuilder)
25.     {
26.         // Breaking change #2 – Default discriminator property changed
27.         // from "Discriminator" to "$type" in EF Core 9.
28.         // Existing documents already store "Discriminator", so we must
29.         // explicitly keep the old name to avoid data mismatch.
30.         modelBuilder.Entity<Product>()
31.             .HasDiscriminator<string>("Discriminator");
32.     }
33. }
34. 
35. class Product
36. {
37.     public string Id { get; set; } = null!;
38.     public string Name { get; set; } = null!;
39. }
40. 
41. // Preferred long-term fix: convert sync callers to async.
42. class ProductService
43. {
44.     private readonly CosmosDbContext _db;
45.     public ProductService(CosmosDbContext db) => _db = db;
46. 
47.     // ✗  Before (EF8): sync was silently allowed
48.     //     var products = _db.Products.ToList();
49.     //
50.     // ✓  After (EF9): use async to avoid the breaking change entirely
51.     public async Task<List<Product>> GetAllAsync()
52.         => await _db.Products.ToListAsync();
53. }
54.

